import fs from "node:fs";
import path from "node:path";

import { normalizeLabel } from "./normalize";
import type { EvidenceStateTruthKey } from "./types";

export const BANNED_BUNDLE_PHRASES = [
  "synthetic bundle",
  "simulator case",
  "test case",
  "generated by ai",
  "fake case",
  "proof pack",
  "red team",
  "evaluation fixture",
] as const;

export type AuditCaseFingerprint = {
  caseId: string;
  defendant?: string;
  offenceFamily?: string;
  trap?: string;
  layout?: string;
  profile?: string;
  chaseSignature: string;
  itemSignature: string;
  bundleHash: string;
};

export type DiversityDuplicate = {
  caseA: string;
  caseB: string;
  reason: string;
  severity: "blocking" | "warning";
};

export type DiversityReport = {
  disclaimer: string;
  caseCount: number;
  duplicates: DiversityDuplicate[];
  bannedPhraseHits: Array<{ caseId: string; phrase: string; surface: "bundle" | "output" }>;
  offenceFamilySpread: Record<string, number>;
  trapSpread: Record<string, number>;
  layoutSpread: Record<string, number>;
  profileSpread: Record<string, number>;
  topRepeatedChaseLabels: Array<{ label: string; count: number }>;
  topRepeatedDefendantNames: Array<{ name: string; count: number }>;
};

function readJson<T>(filePath: string): T | null {
  if (!fs.existsSync(filePath)) return null;
  try {
    return JSON.parse(fs.readFileSync(filePath, "utf8")) as T;
  } catch {
    return null;
  }
}

function simpleHash(text: string): string {
  const normalized = normalizeLabel(text).slice(0, 400);
  let h = 0;
  for (let i = 0; i < normalized.length; i += 1) {
    h = (h * 31 + normalized.charCodeAt(i)) >>> 0;
  }
  return h.toString(16);
}

export function fingerprintAuditCase(
  caseDir: string,
  caseId: string,
): AuditCaseFingerprint | null {
  const truthPath = path.join(caseDir, "truth-key.json");
  const truth = readJson<EvidenceStateTruthKey & Record<string, unknown>>(truthPath);
  if (!truth) return null;

  const bundleCandidates = [
    path.join(caseDir, "bundle-text.md"),
    path.join(caseDir, "..", "..", "..", "docs", "h4", "simulator-pack-v2", caseId, "bundle-text.md"),
    path.join(caseDir, "..", "..", "..", "docs", "h4", "simulator-pack-v3", caseId, "bundle-text.md"),
    path.join(caseDir, "..", "..", "..", "docs", "h4", "simulator-pack-v4", caseId, "bundle-text.md"),
  ];
  let bundleText = "";
  for (const p of bundleCandidates) {
    if (fs.existsSync(p)) {
      bundleText = fs.readFileSync(p, "utf8");
      break;
    }
  }

  const chase = [...(truth.expectedChaseItems ?? [])].map(normalizeLabel).sort().join("|");
  const items = truth.evidenceItems.map((i) => normalizeLabel(i.evidence_item)).sort().join("|");

  return {
    caseId,
    defendant: truth.profile ? undefined : (truth as { fakeDefendant?: string }).fakeDefendant,
    offenceFamily: truth.offenceFamily,
    trap: String(truth.profile ?? (truth as { redTeamTrapType?: string }).redTeamTrapType ?? ""),
    layout: String((truth as { pdfLayoutType?: string }).pdfLayoutType ?? ""),
    profile: truth.profile,
    chaseSignature: chase,
    itemSignature: items,
    bundleHash: simpleHash(bundleText),
  };
}

export function findDuplicates(fingerprints: AuditCaseFingerprint[]): DiversityDuplicate[] {
  const out: DiversityDuplicate[] = [];
  for (let i = 0; i < fingerprints.length; i += 1) {
    for (let j = i + 1; j < fingerprints.length; j += 1) {
      const a = fingerprints[i]!;
      const b = fingerprints[j]!;

      if (a.bundleHash && a.bundleHash === b.bundleHash) {
        out.push({ caseA: a.caseId, caseB: b.caseId, reason: "identical_bundle_text_hash", severity: "blocking" });
        continue;
      }

      if (
        a.offenceFamily &&
        a.offenceFamily === b.offenceFamily &&
        a.trap &&
        a.trap === b.trap &&
        a.layout &&
        a.layout === b.layout
      ) {
        out.push({
          caseA: a.caseId,
          caseB: b.caseId,
          reason: `same offence+trap+layout (${a.offenceFamily}/${a.trap}/${a.layout})`,
          severity: "warning",
        });
      }

      if (a.itemSignature === b.itemSignature && a.chaseSignature === b.chaseSignature && a.itemSignature.length > 40) {
        out.push({
          caseA: a.caseId,
          caseB: b.caseId,
          reason: "same truth-key items and chase labels",
          severity: "blocking",
        });
      }
    }
  }
  return out;
}

export function scanBannedPhrases(caseId: string, bundleText: string, outputText: string): DiversityDuplicate[] {
  const hits: DiversityDuplicate[] = [];
  const bundleLower = bundleText.toLowerCase();
  const outputLower = outputText.toLowerCase();
  for (const phrase of BANNED_BUNDLE_PHRASES) {
    if (bundleLower.includes(phrase)) {
      hits.push({
        caseA: caseId,
        caseB: phrase,
        reason: `banned phrase in bundle: "${phrase}"`,
        severity: "blocking",
      });
    }
    if (outputLower.includes(phrase)) {
      hits.push({
        caseA: caseId,
        caseB: phrase,
        reason: `banned phrase in output: "${phrase}"`,
        severity: "blocking",
      });
    }
  }
  return hits;
}

export function buildDiversityReport(casesRoot: string): DiversityReport {
  const caseIds = fs
    .readdirSync(casesRoot, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => d.name)
    .sort();

  const fingerprints: AuditCaseFingerprint[] = [];
  const bannedPhraseHits: DiversityReport["bannedPhraseHits"] = [];
  const offenceFamilySpread: Record<string, number> = {};
  const trapSpread: Record<string, number> = {};
  const layoutSpread: Record<string, number> = {};
  const profileSpread: Record<string, number> = {};
  const chaseLabelCounts = new Map<string, number>();
  const defendantCounts = new Map<string, number>();

  for (const caseId of caseIds) {
    const caseDir = path.join(casesRoot, caseId);
    const fp = fingerprintAuditCase(caseDir, caseId);
    if (!fp) continue;
    fingerprints.push(fp);

    if (fp.offenceFamily) offenceFamilySpread[fp.offenceFamily] = (offenceFamilySpread[fp.offenceFamily] ?? 0) + 1;
    if (fp.trap) trapSpread[fp.trap] = (trapSpread[fp.trap] ?? 0) + 1;
    if (fp.layout) layoutSpread[fp.layout] = (layoutSpread[fp.layout] ?? 0) + 1;
    if (fp.profile) profileSpread[fp.profile] = (profileSpread[fp.profile] ?? 0) + 1;

    const truth = readJson<EvidenceStateTruthKey>(path.join(caseDir, "truth-key.json"));
    for (const c of truth?.expectedChaseItems ?? []) {
      const key = normalizeLabel(c);
      chaseLabelCounts.set(key, (chaseLabelCounts.get(key) ?? 0) + 1);
    }

    const output = readJson<{ fiveAnswersEvidenceRows?: Array<{ label: string }> }>(
      path.join(caseDir, "casebrain-output.json"),
    );
    const bundlePath = path.join(caseDir, "bundle-text.md");
    const bundleText = fs.existsSync(bundlePath) ? fs.readFileSync(bundlePath, "utf8") : "";
    const outputText = JSON.stringify(output ?? {});
    for (const d of scanBannedPhrases(caseId, bundleText, outputText)) {
      bannedPhraseHits.push({ caseId, phrase: d.caseB, surface: d.reason.includes("output") ? "output" : "bundle" });
    }

    const defendant = (truth as { fakeDefendant?: string } | null)?.fakeDefendant;
    if (defendant) defendantCounts.set(defendant, (defendantCounts.get(defendant) ?? 0) + 1);
  }

  const topRepeatedChaseLabels = [...chaseLabelCounts.entries()]
    .filter(([, n]) => n > 3)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 15)
    .map(([label, count]) => ({ label, count }));

  const topRepeatedDefendantNames = [...defendantCounts.entries()]
    .filter(([, n]) => n > 1)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 15)
    .map(([name, count]) => ({ name, count }));

  return {
    disclaimer: "Controlled/synthetic audit only — not solicitor-reviewed real-world audit.",
    caseCount: fingerprints.length,
    duplicates: findDuplicates(fingerprints),
    bannedPhraseHits,
    offenceFamilySpread,
    trapSpread,
    layoutSpread,
    profileSpread,
    topRepeatedChaseLabels,
    topRepeatedDefendantNames,
  };
}
